import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';

interface Staff {
  id: number;
  firstName: string;
  lastName: string;
  email: string;
  role: string;
  department: string;
}

export default function StaffList() {
  const [staff, setStaff] = useState<Staff[]>([]);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // TODO: Replace with actual API call
    const mockStaff: Staff[] = [
      { id: 1, firstName: 'John', lastName: 'Doe', email: 'john@example.com', role: 'Manager', department: 'IT' },
      { id: 2, firstName: 'Jane', lastName: 'Smith', email: 'jane@example.com', role: 'Developer', department: 'IT' },
      { id: 3, firstName: 'Bob', lastName: 'Johnson', email: 'bob@example.com', role: 'HR', department: 'HR' },
    ];
    
    setStaff(mockStaff);
    setLoading(false);
  }, []);

  const filteredStaff = staff.filter(s =>
    `${s.firstName} ${s.lastName}`.toLowerCase().includes(search.toLowerCase()) ||
    s.email.toLowerCase().includes(search.toLowerCase())
  );

  if (loading) {
    return <div className="p-6">Loading...</div>;
  }

  return (
    <div className="p-6 space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-3xl font-bold">Staff Directory</h1>
        <Link to="/staff/create">
          <Button>Add Staff</Button>
        </Link>
      </div>

      <div>
        <Input
          placeholder="Search by name or email..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="max-w-md"
        />
      </div>

      <div className="grid gap-4">
        {filteredStaff.map(s => (
          <Link key={s.id} to={`/staff/${s.id}`}>
            <div className="p-4 border rounded-lg hover:shadow-lg transition">
              <div className="flex justify-between items-start">
                <div>
                  <h3 className="font-semibold">{s.firstName} {s.lastName}</h3>
                  <p className="text-sm text-gray-600">{s.email}</p>
                  <p className="text-sm text-gray-600">{s.role} - {s.department}</p>
                </div>
              </div>
            </div>
          </Link>
        ))}
      </div>

      {filteredStaff.length === 0 && (
        <div className="text-center py-8 text-gray-500">
          No staff members found
        </div>
      )}
    </div>
  );
}
